59	// Version control
60	#define RIME_STRUCT_INIT(Type, var) \
61	  ((var).data_size = sizeof(Type) - sizeof((var).data_size))
62	#define RIME_STRUCT_HAS_MEMBER(var, member)           \
63	  ((int)(sizeof((var).data_size) + (var).data_size) > \
64	   (char*)&member - (char*)&var)
65	#define RIME_STRUCT_CLEAR(var) \
66	  memset((char*)&(var) + sizeof((var).data_size), 0, (var).data_size)
67	
68	//! Define a variable of Type
69	#define RIME_STRUCT(Type, var) \
70	  Type var = {0};              \
71	  RIME_STRUCT_INIT(Type, var);
72	
73	// tests that member is a non-null pointer in self-versioned struct *p.
74	#define RIME_PROVIDED(p, member) \
75	  ((p) && RIME_STRUCT_HAS_MEMBER(*(p), (p)->member) && (p)->member)
