15	  printf("schema: %s / %s\n", status->schema_id, status->schema_name);
16	  printf("status: ");
17	  if (status->is_disabled)
18	    printf("disabled ");
19	  if (status->is_composing)
20	    printf("composing ");
21	  if (status->is_ascii_mode)
22	    printf("ascii ");
23	  if (status->is_full_shape)
24	    printf("full_shape ");
25	  if (status->is_simplified)
26	    printf("simplified ");
27	  printf("\n");
