29	
30	void print_composition(RimeComposition* composition) {
31	  const char* preedit = composition->preedit;
32	  if (!preedit)
33	    return;
34	  size_t len = strlen(preedit);
35	  size_t start = composition->sel_start;
36	  size_t end = composition->sel_end;
37	  size_t cursor = composition->cursor_pos;
38	  for (size_t i = 0; i <= len; ++i) {
39	    if (start < end) {
40	      if (i == start) {
41	        putchar('[');
42	      } else if (i == end) {
43	        putchar(']');
44	      }
45	    }
46	    if (i == cursor)
47	      putchar('|');
48	    if (i < len)
49	      putchar(preedit[i]);
50	  }
51	  printf("\n");
52	}
53	
54	void print_menu(RimeMenu* menu) {
55	  if (menu->num_candidates == 0)
56	    return;
57	  printf("page: %d%c (of size %d)\n", menu->page_no + 1,
58	         menu->is_last_page ? '$' : ' ', menu->page_size);
59	  for (int i = 0; i < menu->num_candidates; ++i) {
